"""Agent-loop: модель сама вызывает tool'ы через OpenAI tool-calling API."""

from __future__ import annotations

import json
import sys
from dataclasses import dataclass
from typing import Any

from ai_analyst.config import Config, load_config
from ai_analyst.db import OracleClient
from ai_analyst.llm import build_client
from ai_analyst.prompts import SYSTEM_PROMPT
from ai_analyst.tools import (
    TOOL_SCHEMAS,
    ToolHandler,
    build_tool_handlers,
    json_dump,
)

DEFAULT_MAX_STEPS = 12


@dataclass
class AgentResult:
    text: str
    supporting_data: dict[str, Any]
    steps_used: int

    def to_dict(self) -> dict[str, Any]:
        return {
            "text": self.text,
            "supporting_data": self.supporting_data,
            "steps_used": self.steps_used,
        }


def _eprint(msg: str) -> None:
    print(msg, file=sys.stderr, flush=True)


class Agent:
    """Минималистичный tool-calling agent.

    Шаг = вызов chat.completions.create. Модель выбирает следующий tool сама,
    цикл завершается либо вызовом final_answer, либо исчерпанием max_steps.
    """

    def __init__(
        self,
        config: Config,
        oracle_client: OracleClient,
        *,
        model: str | None = None,
        max_steps: int = DEFAULT_MAX_STEPS,
        verbose: bool = True,
    ):
        self._config = config
        self._oracle = oracle_client
        self._model = model or config.sql_model
        self._max_steps = max_steps
        self._verbose = verbose
        self._llm = build_client(config)
        self._handlers: dict[str, ToolHandler] = build_tool_handlers(oracle_client)

    # --- основной цикл ---------------------------------------------------------

    def run(self, question: str) -> AgentResult:
        if not question or not question.strip():
            raise ValueError("Вопрос пуст.")

        messages: list[dict[str, Any]] = [
            {"role": "system", "content": SYSTEM_PROMPT},
            {"role": "user", "content": question.strip()},
        ]

        for step in range(1, self._max_steps + 1):
            if self._verbose:
                _eprint(f"[step {step}] → LLM call")

            response = self._llm.chat.completions.create(
                model=self._model,
                messages=messages,  # type: ignore[arg-type]
                tools=TOOL_SCHEMAS,  # type: ignore[arg-type]
                tool_choice="auto",
                temperature=0.0,
            )

            choice = response.choices[0]
            msg = choice.message
            tool_calls = list(getattr(msg, "tool_calls", None) or [])

            # Сохраняем assistant-сообщение (с tool_calls) в историю.
            messages.append(_assistant_msg_to_dict(msg))

            if not tool_calls:
                # Модель ответила текстом без tool_call. Это нарушение протокола,
                # но используем контент как фолбэк, если он не пуст.
                fallback = (msg.content or "").strip()
                if fallback:
                    if self._verbose:
                        _eprint("[warn] LLM ответил текстом без final_answer — использую как fallback")
                    return AgentResult(text=fallback, supporting_data={}, steps_used=step)
                # Подтолкнём к вызову final_answer.
                messages.append({
                    "role": "user",
                    "content": (
                        "Пожалуйста, продолжай работу через tool calls. "
                        "Если все данные собраны — вызови final_answer."
                    ),
                })
                continue

            final_result: AgentResult | None = None

            for tc in tool_calls:
                name = tc.function.name
                raw_args = tc.function.arguments or "{}"
                try:
                    args = json.loads(raw_args) if isinstance(raw_args, str) else dict(raw_args)
                except json.JSONDecodeError as exc:
                    tool_output: dict[str, Any] = {
                        "error": f"JSON decode error в arguments: {exc}",
                        "raw": raw_args[:500] if isinstance(raw_args, str) else str(raw_args),
                    }
                    messages.append({
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "content": json_dump(tool_output),
                    })
                    continue

                handler = self._handlers.get(name)
                if handler is None:
                    tool_output = {"error": f"Неизвестный tool: {name}"}
                else:
                    if self._verbose:
                        _eprint(f"[step {step}] tool: {name} args={_short(args)}")
                    try:
                        tool_output = handler(args)
                    except Exception as exc:  # noqa: BLE001
                        tool_output = {"error": f"Tool {name} crashed: {type(exc).__name__}: {exc}"}
                    if self._verbose:
                        _eprint(f"[step {step}] tool {name} → {_short(tool_output)}")

                messages.append({
                    "role": "tool",
                    "tool_call_id": tc.id,
                    "content": json_dump(tool_output),
                })

                if isinstance(tool_output, dict) and tool_output.get("__final_answer__"):
                    final_result = AgentResult(
                        text=str(tool_output.get("text", "")),
                        supporting_data=dict(tool_output.get("supporting_data") or {}),
                        steps_used=step,
                    )

            if final_result is not None:
                return final_result

        # Превышен лимит шагов.
        raise RuntimeError(
            f"Агент не сошёлся за {self._max_steps} шагов. "
            f"Это может означать, что модель не вызвала final_answer."
        )


# --- helpers -------------------------------------------------------------------

def _assistant_msg_to_dict(msg: Any) -> dict[str, Any]:
    """Приводит OpenAI ChatCompletionMessage к dict в формате, понимаемом API."""
    out: dict[str, Any] = {"role": "assistant", "content": msg.content or ""}
    tool_calls = getattr(msg, "tool_calls", None) or []
    if tool_calls:
        out["tool_calls"] = [
            {
                "id": tc.id,
                "type": "function",
                "function": {
                    "name": tc.function.name,
                    "arguments": tc.function.arguments or "{}",
                },
            }
            for tc in tool_calls
        ]
    return out


def _short(value: Any, limit: int = 400) -> str:
    s = json_dump(value)
    return s if len(s) <= limit else s[:limit] + "…"


# --- top-level helper ----------------------------------------------------------

def run_question(
    question: str,
    *,
    config: Config | None = None,
    verbose: bool = True,
    max_steps: int = DEFAULT_MAX_STEPS,
) -> AgentResult:
    """Удобная обёртка: загрузить config, открыть Oracle, прогнать вопрос, закрыть."""
    cfg = config or load_config()
    with OracleClient(cfg) as oracle:
        agent = Agent(cfg, oracle, max_steps=max_steps, verbose=verbose)
        return agent.run(question)

"""Реализация tool'ов для агента + JSON Schema для OpenAI tool-calling API."""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any, Callable

from ai_analyst.db import OracleClient, SqlValidationError
from metadata import get_sql_examples, get_table_metadata


# --- Public types --------------------------------------------------------------

ToolResult = dict[str, Any]
ToolHandler = Callable[[dict[str, Any]], ToolResult]


@dataclass
class FinalAnswer:
    """Маркерный объект — агент готов завершиться."""

    text: str
    supporting_data: dict[str, Any] = field(default_factory=dict)


# --- inspect_schema ------------------------------------------------------------

def _compact_field(name: str, descriptor: dict[str, Any]) -> dict[str, Any]:
    """Сжимает field-descriptor из metadata.py до самого нужного для LLM."""
    keep = (
        "type",
        "description",
        "category",
        "is_key",
        "operation_currency",
        "result_currency_equivalent",
        "aggregation_between_clients",
        "aggregation_between_month",
    )
    out: dict[str, Any] = {"name": name}
    for k in keep:
        if k in descriptor:
            out[k] = descriptor[k]
    return out


def inspect_schema(args: dict[str, Any]) -> ToolResult:
    """Возвращает описание таблицы и её колонок из metadata.py."""
    table = (args.get("table") or "client_product").strip().lower()
    try:
        meta = get_table_metadata(table)
    except ValueError as exc:
        return {"error": str(exc)}

    fields = meta.get("fields", {})
    return {
        "table_name": meta.get("table_name", table),
        "description": (meta.get("description") or "").strip(),
        "fields": [_compact_field(n, d) for n, d in fields.items()],
        "sql_examples": get_sql_examples(table),
    }


# --- execute_sql ---------------------------------------------------------------

def make_execute_sql(client: OracleClient, *, max_rows: int = 1000) -> ToolHandler:
    """Фабрика handler'а execute_sql, замыкающего OracleClient."""

    def _handler(args: dict[str, Any]) -> ToolResult:
        sql = args.get("sql")
        if not isinstance(sql, str) or not sql.strip():
            return {"error": "Параметр `sql` обязателен и должен быть непустой строкой."}
        try:
            limit = int(args.get("max_rows") or max_rows)
        except (TypeError, ValueError):
            limit = max_rows
        limit = max(1, min(limit, max_rows))
        try:
            result = client.execute(sql, max_rows=limit)
        except SqlValidationError as exc:
            return {"error": f"SQL validation: {exc}", "sql": sql}
        except Exception as exc:  # noqa: BLE001 — пробрасываем в LLM текст ошибки
            return {
                "error": f"Oracle error: {type(exc).__name__}: {exc}",
                "sql": sql,
            }
        return {"sql": sql, **result.to_dict()}

    return _handler


# --- validate_result -----------------------------------------------------------

def validate_result(args: dict[str, Any]) -> ToolResult:
    """Sanity-проверки результата.

    Принимает `result` (как вернул execute_sql) и опциональные `expectations`:
      - min_rows / max_rows: ожидаемый размер
      - non_null_columns: список колонок, в которых не должно быть None в первой строке
      - numeric_columns: список колонок, которые должны содержать число (не None) в первой строке
      - non_negative_columns: числовые колонки, которые должны быть >= 0
    Возвращает {"ok": bool, "issues": [...], "summary": {...}}.
    """
    result = args.get("result")
    if not isinstance(result, dict):
        return {"ok": False, "issues": ["`result` должен быть объектом (dict)."]}
    expectations = args.get("expectations") or {}
    columns = result.get("columns") or []
    rows = result.get("rows") or []

    issues: list[str] = []

    # размер
    row_count = result.get("row_count", len(rows))
    min_rows = expectations.get("min_rows")
    max_rows = expectations.get("max_rows")
    if isinstance(min_rows, int) and row_count < min_rows:
        issues.append(f"Строк {row_count} < ожидаемого минимума {min_rows}.")
    if isinstance(max_rows, int) and row_count > max_rows:
        issues.append(f"Строк {row_count} > ожидаемого максимума {max_rows}.")

    if row_count == 0:
        issues.append("Пустой результат — возможно слишком жёсткий фильтр или нет данных.")

    # Колонко-ориентированные проверки — только если есть хоть одна строка.
    if rows:
        first = rows[0]
        col_idx = {c.upper(): i for i, c in enumerate(columns)}

        for col in expectations.get("non_null_columns") or []:
            i = col_idx.get(str(col).upper())
            if i is None:
                issues.append(f"Колонка {col!r} не найдена в результате.")
            elif first[i] is None:
                issues.append(f"Колонка {col!r} = NULL в первой строке.")

        for col in expectations.get("numeric_columns") or []:
            i = col_idx.get(str(col).upper())
            if i is None:
                issues.append(f"Колонка {col!r} не найдена в результате.")
            elif not isinstance(first[i], (int, float)):
                issues.append(f"Колонка {col!r} не числовая (значение: {first[i]!r}).")

        for col in expectations.get("non_negative_columns") or []:
            i = col_idx.get(str(col).upper())
            if i is None:
                issues.append(f"Колонка {col!r} не найдена в результате.")
            elif isinstance(first[i], (int, float)) and first[i] < 0:
                issues.append(f"Колонка {col!r} отрицательная: {first[i]}.")

    return {
        "ok": not issues,
        "issues": issues,
        "summary": {
            "row_count": row_count,
            "columns": columns,
            "truncated": result.get("truncated", False),
        },
    }


# --- final_answer --------------------------------------------------------------

def final_answer(args: dict[str, Any]) -> ToolResult:
    """Маркер: агент готов вернуть финальный текст пользователю."""
    text = args.get("text") or ""
    if not isinstance(text, str) or not text.strip():
        return {"error": "Поле `text` обязательно и не должно быть пустым."}
    supporting = args.get("supporting_data")
    if supporting is None:
        supporting = {}
    if not isinstance(supporting, dict):
        return {"error": "Поле `supporting_data` должно быть объектом (dict)."}
    # Сериализованный маркер. Agent-loop опознаёт его и прерывается.
    return {
        "__final_answer__": True,
        "text": text.strip(),
        "supporting_data": supporting,
    }


# --- JSON Schema для OpenAI tools API ------------------------------------------

TOOL_SCHEMAS: list[dict[str, Any]] = [
    {
        "type": "function",
        "function": {
            "name": "inspect_schema",
            "description": (
                "Получить описание таблицы и её колонок из metadata.py. "
                "Используй ОБЯЗАТЕЛЬНО перед написанием первого SQL, "
                "чтобы выбрать правильные поля. Возвращает структуру с "
                "table_name, description, fields[], sql_examples[]."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "table": {
                        "type": "string",
                        "description": "Имя таблицы. По умолчанию client_product.",
                    }
                },
                "required": [],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "execute_sql",
            "description": (
                "Выполнить read-only Oracle SQL (SELECT/WITH) и получить таблицу "
                "результатов. Разрешён ровно один запрос без точки с запятой. "
                "Используй Oracle-синтаксис: DATE 'YYYY-MM-DD', FETCH FIRST N ROWS ONLY, "
                "EXTRACT(YEAR FROM ...), и т.д."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "sql": {
                        "type": "string",
                        "description": "Один SELECT/WITH запрос, без trailing `;`.",
                    },
                    "max_rows": {
                        "type": "integer",
                        "description": "Лимит строк (по умолчанию 1000).",
                    },
                },
                "required": ["sql"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "validate_result",
            "description": (
                "Sanity-проверка результата execute_sql. Передай объект result "
                "(как пришёл из execute_sql) и expectations: ожидаемый размер, "
                "имена ненулевых/числовых/неотрицательных колонок."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "result": {
                        "type": "object",
                        "description": "Объект {columns, rows, row_count, truncated}.",
                    },
                    "expectations": {
                        "type": "object",
                        "properties": {
                            "min_rows": {"type": "integer"},
                            "max_rows": {"type": "integer"},
                            "non_null_columns": {
                                "type": "array",
                                "items": {"type": "string"},
                            },
                            "numeric_columns": {
                                "type": "array",
                                "items": {"type": "string"},
                            },
                            "non_negative_columns": {
                                "type": "array",
                                "items": {"type": "string"},
                            },
                        },
                    },
                },
                "required": ["result"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "final_answer",
            "description": (
                "Финализировать ответ пользователю. Вызывай ТОЛЬКО когда: "
                "(1) выполнил SQL и получил цифры, (2) провёл validate_result, "
                "(3) готов сформулировать ответ на русском с конкретными числами "
                "и интерпретацией. Текст должен быть самодостаточным."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "text": {
                        "type": "string",
                        "description": "Финальный ответ пользователю на русском языке.",
                    },
                    "supporting_data": {
                        "type": "object",
                        "description": (
                            "Машиночитаемая выжимка: использованный SQL, "
                            "ключевые числа, найденные строки."
                        ),
                    },
                },
                "required": ["text"],
            },
        },
    },
]


def build_tool_handlers(
    oracle_client: OracleClient, *, max_rows: int = 1000
) -> dict[str, ToolHandler]:
    """Собирает dispatcher {tool_name -> handler}."""
    return {
        "inspect_schema": inspect_schema,
        "execute_sql": make_execute_sql(oracle_client, max_rows=max_rows),
        "validate_result": validate_result,
        "final_answer": final_answer,
    }


def json_dump(value: Any) -> str:
    """Безопасный JSON-дамп с поддержкой нестандартных типов (для логов)."""
    return json.dumps(value, ensure_ascii=False, default=str)

"""Тонкая обёртка над oracledb с read-only выполнением SELECT-запросов."""

from __future__ import annotations

import datetime as _dt
import decimal
import re
from contextlib import contextmanager
from dataclasses import dataclass
from typing import Any, Iterator

import oracledb

from ai_analyst.config import Config

# Жёсткий лимит, чтобы случайный SELECT * не утянул всё в память.
DEFAULT_MAX_ROWS = 1000

# Запретные ключевые слова. SELECT (включая WITH) — разрешён,
# DML/DDL и многоточечные стейтменты — нет.
_FORBIDDEN_PATTERNS = [
    re.compile(r"\b(insert|update|delete|merge|truncate|drop|alter|create|grant|revoke|begin|call|execute)\b", re.IGNORECASE),
]


class SqlValidationError(ValueError):
    """SQL не прошёл проверку на read-only."""


def _strip_sql(sql: str) -> str:
    """Убирает trailing-точки-с-запятой и whitespace."""
    return sql.strip().rstrip(";").strip()


def assert_readonly_sql(sql: str) -> str:
    """Проверяет, что SQL — одиночный SELECT/WITH-запрос без побочных эффектов.

    Возвращает нормализованный SQL (без trailing `;`).
    """
    if not sql or not sql.strip():
        raise SqlValidationError("Пустой SQL")

    normalized = _strip_sql(sql)
    # Multi-statement: после нормализации не должно остаться `;` внутри строки.
    if ";" in normalized:
        raise SqlValidationError(
            "Multi-statement SQL запрещён. Передавай ровно один SELECT/WITH."
        )

    lowered = normalized.lstrip("(").lstrip().lower()
    if not (lowered.startswith("select") or lowered.startswith("with")):
        raise SqlValidationError(
            "Разрешены только SELECT / WITH запросы (read-only)."
        )

    for pat in _FORBIDDEN_PATTERNS:
        match = pat.search(normalized)
        if match:
            raise SqlValidationError(
                f"В SQL найдено запрещённое ключевое слово: {match.group(0)!r}"
            )

    return normalized


def _python_value(value: Any) -> Any:
    """Конвертирует Oracle-типы в JSON-сериализуемые Python-значения."""
    if value is None:
        return None
    if isinstance(value, decimal.Decimal):
        if value == value.to_integral_value():
            return int(value)
        return float(value)
    if isinstance(value, (_dt.datetime, _dt.date)):
        return value.isoformat()
    if isinstance(value, bytes):
        try:
            return value.decode("utf-8")
        except UnicodeDecodeError:
            return value.hex()
    return value


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    row_count: int
    truncated: bool

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
        }


class OracleClient:
    """Lazy-инициализируемое соединение с Oracle.

    Open per CLI run, closed на context exit / .close().
    """

    def __init__(self, config: Config):
        self._config = config
        self._conn: oracledb.Connection | None = None

    def connect(self) -> oracledb.Connection:
        if self._conn is None:
            self._conn = oracledb.connect(
                user=self._config.oracle_username,
                password=self._config.oracle_password,
                dsn=self._config.oracle_dsn,
            )
        return self._conn

    def close(self) -> None:
        if self._conn is not None:
            try:
                self._conn.close()
            finally:
                self._conn = None

    @contextmanager
    def cursor(self) -> Iterator[oracledb.Cursor]:
        conn = self.connect()
        cur = conn.cursor()
        try:
            yield cur
        finally:
            cur.close()

    def execute(self, sql: str, *, max_rows: int = DEFAULT_MAX_ROWS) -> QueryResult:
        normalized = assert_readonly_sql(sql)
        with self.cursor() as cur:
            cur.execute(normalized)
            columns: list[str] = [str(d[0]) for d in (cur.description or [])]
            raw_rows = cur.fetchmany(max_rows + 1)
            truncated = len(raw_rows) > max_rows
            rows = [[_python_value(v) for v in row] for row in raw_rows[:max_rows]]
            return QueryResult(
                columns=columns,
                rows=rows,
                row_count=len(rows),
                truncated=truncated,
            )

    def __enter__(self) -> "OracleClient":
        self.connect()
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        self.close()

"""Загрузка конфигурации из .env / окружения."""

from __future__ import annotations

import os
from dataclasses import dataclass
from pathlib import Path

from dotenv import load_dotenv


@dataclass(frozen=True)
class Config:
    oracle_username: str
    oracle_password: str
    oracle_dsn: str
    api_url: str
    api_key: str
    sql_model: str
    response_model: str

    @property
    def has_oracle_credentials(self) -> bool:
        return bool(self.oracle_username and self.oracle_password and self.oracle_dsn)


def _require(name: str) -> str:
    value = os.environ.get(name, "").strip()
    if not value:
        raise RuntimeError(
            f"Переменная окружения {name} не задана. "
            f"Проверь .env в корне проекта."
        )
    return value


def load_config(env_path: str | os.PathLike[str] | None = None) -> Config:
    """Загружает .env (если указан или найден рядом с CWD) и возвращает Config."""
    if env_path is None:
        candidate = Path.cwd() / ".env"
        if candidate.is_file():
            load_dotenv(candidate, override=False)
    else:
        load_dotenv(env_path, override=False)

    return Config(
        oracle_username=_require("AI_ANALYST_ORACLE_USERNAME"),
        oracle_password=_require("AI_ANALYST_ORACLE_PASSWORD"),
